static irqreturn_t v3d_irq(int irq, void *arg)
{
struct v3d_dev *v3d = arg;
u32 intsts;
irqreturn_t status = IRQ_NONE;
// Read the interrupt status from the V3D core
intsts = V3D_CORE_READ(0, V3D_IRQ_STATUS);
// Acknowledge the interrupts by writing the status back to the clear register
V3D_CORE_WRITE(0, V3D_IRQ_CLEAR, intsts);
// Check if the interrupt status indicates an out-of-memory condition
if (intsts & V3D_IRQ_OOM) {
schedule_work(&v3d->overflow_mem_work);
status |= IRQ_HANDLED;
}
// Check if the interrupt status indicates that the binning process is done
if (intsts & V3D_IRQ_BDONE) {
struct v3d_fence *b Fence = to_v3d_fence(v3d->bin_job->base.irq_fence);
trace_v3d_bcl_irq(&v3d->drm, b_Fence->seqno);
dma_fence_signal(&b_Fence->base);
status |= IRQ_HANDLED;
}
// Check if the interrupt status indicates that the rendering process is done
if (intsts & V3D_IRQ_RDONE) {
struct v3d_fence *r_Fence = to_v3d_fence(v3d->render_job->base.irq_fence);
trace_v3d_rcl_irq(&v3d->drm, r_Fence->seqno);
dma_fence_signal(&r_Fence->base);
status |= IRQ_HANDLED;
}
// Check if the interrupt status indicates that the compute shader dispatch is done
if (intsts & V3D_IRQ_CDONE) {
struct v3d_fence *cd_Fence = to_v3d_fence(v3d->csd_job->base.irq_fence);
trace_v3d_csd_irq(&v3d->drm, cd_Fence->seqno);
dma_fence_signal(&cd_Fence->base);
status |= IRQ_HANDLED;
}
// Check for GMP violation interrupt and log an error if it occurs
if (v3d->single_irq_line && (intsts & V3D_IRQ_MALI_GMPP_ERROR)) {
dev_err(v3d->drm.dev, "GMP Violation\n");
status |= IRQ_HANDLED;
}
// If using a single IRQ line and no core IRQs were handled, check the hub for MMU IRQs
if (v3d->single_irq_line && !status) {
status = v3d_hub_irq(irq, arg);
}
return status;
}
