// Set the size of the outbound window
ep->ob_window[i].page_size = resource_size(ob_res);
ep->ob_window[i].phys_offset = 0;
ep->ob_window[i].cpu_addr = (void *)ob_res->start;
ep->ob_window[i].len = resource_size(ob_res);
// Increment the outbound window count
ep->num_ob_windows++;
}
// Update the number of outbound windows in the endpoint structure
return 0;
}

