// If reading the file fails, free the allocated memory and return NULL
if (status < 0) {
free(symlink);
return NULL;
}
}
// Null-terminate the symlink string
symlink[le32_to_cpu(diro->inode.size)] = '\0';
// Return the symlink string
return symlink;
