}
format = runtime_playback->oss.format;
width = snd_pcm_format Physical Width(format);
if (runtime_playback->oss.buffer_used) {
#ifdef OSS_DEBUG
pcm_dbg(runtime_playback->pcm, "OSS_SYNC: buffer_used = %u\n",
runtime_playback->oss.buffer_used);
