static ssize_t queue_attr_store(struct kobject *kobj, struct attribute *attr, const char *page, size_t length) {
// Convert the attribute to a queue_sysfs_entry structure
struct queue_sysfs_entry *entry = to_queue(attr);
// Retrieve the gendisk structure from the kobject
struct gendisk *disk = container_of(kobj, struct gendisk, queue_kobj);
// Get the request_queue from the gendisk
struct request_queue *q = disk->queue;
// Declare a variable to store the result of the operation
ssize_t res;
// Check if there are no store_limit and store functions available
if (!entry->store_limit && !entry->store)
// Return an error if neither function is available
return -EINVAL;
// If the attribute requires loading a module, do it before freezing the queue
if (entry->load_module)
// Load the module using the provided function
entry->load_module(disk, page, length);
// Lock the sysfs mutex to ensure exclusive access
mutex_lock(&q->sysfs_lock);
// Freeze the request queue to prevent new requests
blk_mq_freeze_queue(q);
// Check if there is a store_limit function available
if (entry->store_limit) {
// Start updating the queue limits
struct queue_limits lim = queue_limits_start_update(q);
// Call the store_limit function and store the result
res = entry->store_limit(disk, page, length, &lim);
// If the result is negative, cancel the update
if (res < 0) {
// Cancel the queue limits update
queue_limits_cancel_update(q);
} else {
// Commit the queue limits update
queue_limits_commit_update(q, &lim);
// If the update was successful, set the result to the length
if (!res)
res = length;
}
} else {
// Call the store function and store the result
res = entry->store(disk, page, length);
}
// Unfreeze the request queue to allow new requests
blk_mq_unfreeze_queue(q);
// Unlock the sysfs mutex
mutex_unlock(&q->sysfs_lock);
// Return the result of the operation
return res;
}
