struct drm_i915_private *dev_priv = to_i915(encoder->base.dev);
// Convert the CRTC state to an intel_crtc structure
struct intel_crtc *crtc = to_intel_crtc(crtc_state->uapi.crtc);
// Retrieve the pipe associated with the CRTC
enum pipe pipe = crtc->pipe;
// Warn if the CRTC state does not have a PCH encoder
if (!crtc_state->has_pch_encoder)
drm_warn(&dev_priv->drm, "CRTC state lacks PCH encoder!\n");
// Enable the transcoder function for the encoder
intel_ddi_enable_transcoder_func(encoder, crtc_state);
// Enable the transcoder for the CRTC state
intel_enable_transcoder(crtc_state);
// Enable the PCH for the given state and CRTC
lpt_pch_enable(state, crtc);
// Enable vblank for the CRTC state
intel_crtc_vblank_on(crtc_state);
// Set the DPMS mode to ON for the encoder and CRTC state
intel_crt_set_dpms(encoder, crtc_state, DRM_MODE_DPMS_ON);
// Wait for the next vblank event on the CRTC
intel_crtc_wait_for_next_vblank(crtc);
// Wait for another vblank event on the CRTC
intel_crtc_wait_for_next_vblank(crtc);
// Enable CPU FIFO underrun reporting for the given pipe
intel_set_cpu_fifo_underrun_reporting(dev_priv, pipe, true);
// Enable PCH FIFO underrun reporting for PIPE_A
intel_set_cpu_fifo_underrun_reporting(dev_priv, PIPE_A, true);
}

static void hsw_disable_crt(struct intel_atomic_state *state,
struct intel_encoder *encoder,
const struct intel_crtc_state *old_crtc_state,
const struct drm_connector_state *old_conn_state)
{
/*
* Convert the atomic state to an intel_display structure.
* In our design the display pointer can be obtained via the driver’s private
* structure. Since the atomic state isn’t directly embedded in intel_display,
* we use the encoder’s base device to get to drm_i915_private and then to display.
*/
/* Convert the encoder's base device to a drm_i915_private structure */
struct drm_i915_private *dev_priv = to_i915(encoder->base.dev);
/* Get the intel_display structure from the device private data */
struct intel_display *display = &dev_priv->display;
/*
* Log a warning if the old CRTC state does not have a PCH encoder.
* In our hardware state, the "has_pch_encoder" flag indicates if a PCH (Platform Controller Hub)
* encoder is attached; if not, something unexpected is happening.
*/
if (!old_crtc_state->has_pch_encoder)
drm_WARN_ON(encoder->base.dev, 1);
/*
* Disable PCH FIFO underrun reporting for PIPE_A.
* PIPE_A is assumed to be defined appropriately (e.g. as an enumerator of type enum pipe).
*/
intel_set_pch_fifo_underrun_reporting(dev_priv, PIPE_A, false);
}

