struct rxrpc_peer *rxrpc_lookup_peer(struct rxrpc_local *local, struct sockaddr_rxrpc *srx, gfp_t gfp)
{
struct rxrpc_peer *peer, *candidate;
struct rxrpc_net *rxnet = local->rxnet;
unsigned long hash_key = rxrpc_peer_hash_key(local, srx);
_enter("{%pISp}", &srx->transport);
// Lock the RCU read-side critical section to safely traverse the peer list
rcu_read_lock();
// Attempt to find the peer in the hash table using the calculated hash key
peer = __rxrpc_lookup_peer_rcu(local, srx, hash_key);
// If the peer is found, attempt to increment its reference count
if (peer && !rxrpc_get_peer_maybe(peer, rxrpc_peer_get_lookup_client))
// If the reference count increment fails, set peer to NULL
peer = NULL;
// Unlock the RCU read-side critical section
rcu_read_unlock();
// If the peer was not found in the hash table
if (!peer) {
// Create a new candidate peer object
candidate = rxrpc_create_peer(local, srx, hash_key, gfp);
// If candidate creation fails, return NULL
if (!candidate) {
_leave(" = NULL [nomem]");
return NULL;
}
// Lock the peer hash table to safely modify it
spin_lock(&rxnet->peer_hash_lock);
// Recheck the hash table to ensure no race condition occurred
peer = __rxrpc_lookup_peer_rcu(local, srx, hash_key);
// If the peer is found, attempt to increment its reference count
if (peer && !rxrpc_get_peer_maybe(peer, rxrpc_peer_get_lookup_client))
// If the reference count increment fails, set peer to NULL
peer = NULL;
// If the peer is still not found, add the candidate to the hash table
if (!peer) {
hash_add_rcu(rxnet->peer_hash,
&candidate->hash_link, hash_key);
// Add the candidate to the keepalive list
list_add_tail(&candidate->keepalive_link,
&rxnet->peer_keepalive_new);
}
// Unlock the peer hash table
spin_unlock(&rxnet->peer_hash_lock);
// If a peer was found, free the candidate
if (peer)
rxrpc_free_peer(candidate);
else
// Otherwise, use the candidate as the peer
peer = candidate;
}
// Log the result and return the peer
_leave(" = %p {u=%d}", peer, refcount_read(&peer->ref));
return peer;
}

static struct sock *l2cap_sock_alloc(struct net *net, struct socket *sock,
int proto, gfp_t prio, int kern)
{
struct sock *sk;
struct l2cap_chan *chan;
/* Allocate a new socket structure for the Bluetooth protocol */
sk = sk_alloc(net, PF_BLUETOOTH, prio, &l2cap_proto, kern);
/* If the socket allocation fails, return NULL */
if (!sk)
return NULL;
/* Initialize the socket data with the provided socket and the newly allocated socket structure */
sock_init_data_uid(sock, sk, make_kuid(&init_user_ns, 0));
/* Initialize the accept queue for the Bluetooth socket (here we initialize the rx_busy list) */
INIT_LIST_HEAD(&l2cap_pi(sk)->rx_busy);
/* Set the destructor function for the socket to handle cleanup */
sk->sk_destruct = l2cap_sock_destruct;
/* Set the send timeout for the socket to the L2CAP connection timeout value */
sk->sk_sndtimeo = L2CAP_CONN_TIMEOUT;
/* Reset the SOCK_ZAPPED flag for the socket */
sock_reset_flag(sk, SOCK_ZAPPED);
/* Set the protocol for the socket to the provided protocol value */
sk->sk_protocol = proto;
/* Set the initial state of the socket to BT_OPEN */
sk->sk_state = BT_OPEN;
/* Create a new L2CAP channel for the socket */
chan = l2cap_chan_create();
/* If the channel creation fails, free the socket and return NULL */
if (!chan) {
sk_free(sk);
return NULL;
}
/* Increment the reference count for the newly created L2CAP channel */
l2cap_chan_hold(chan);
/* Associate the L2CAP channel with the socket */
l2cap_pi(sk)->chan = chan;
/* Return the newly allocated and initialized socket */
return sk;
}

