static inline __le16 get_unaligned_le16(const void *p)
{
const uint8_t *ptr = p;
return ptr[0] | (ptr[1] << 8);
}
static inline __le32 get_unaligned_le32(const void *p)
{
const uint8_t *ptr = p;
return ptr[0] | (ptr[1] << 8) | (ptr[2] << 16) | (ptr[3] << 24);
}
int sqfs_inode_size(struct squashfs_base_inode *inode, u32 blk_size)
{
// Determine the inode type by reading the inode_type field
switch (get_unaligned_le16(&inode->inode_type)) {
case SQFS_DIR_TYPE:
// Return the size of a directory inode structure
return sizeof(struct squashfs_dir_inode);
case SQFS_REG_TYPE: {
// Cast the base inode to a regular file inode structure
struct squashfs_reg_inode *reg_inode = (struct squashfs_reg_inode *)inode;
// Read the fragment and file size fields from the regular inode
__le32 fragment = get_unaligned_le32(&reg_inode->fragment);
__le32 file_size = get_unaligned_le32(&reg_inode->file_size);
// Declare a variable to hold the block list size
u32 block_list_size;
// Check if the file is fragmented
if (SQFS_IS_FRAGMENTED(fragment))
// Calculate block list size for fragmented files
block_list_size = (file_size + blk_size - 1) / blk_size;
else
// Calculate block list size for non-fragmented files
block_list_size = (file_size + blk_size - 1) / blk_size + 1;
// Return the total size of the regular inode including the block list
return sizeof(struct squashfs_reg_inode) + block_list_size * sizeof(__le16);
}
case SQFS_LDIR_TYPE: {
// Cast the base inode to a large directory inode structure
struct squashfs_ldir_inode *ldir_inode = (struct squashfs_ldir_inode *)inode;
// Read the i_count field from the large directory inode
__le16 i_count = get_unaligned_le16(&ldir_inode->i_count);
// Initialize variables for index list size and loop counter
u32 index_list_size = 0;
int l = 0;
// Declare a pointer to iterate over directory indices
struct squashfs_directory_index *index_ptr;
// Check if there are no indices
if (i_count == 0)
// Return the size of the large directory inode structure
return sizeof(struct squashfs_ldir_inode);
// Initialize the directory index pointer
index_ptr = ldir_inode->index;
// Iterate over each directory index
while (l < i_count) {
// Read the size of the current directory index
u32 size = get_unaligned_le32(&index_ptr->size);
// Accumulate the total index list size
index_list_size += sizeof(struct squashfs_directory_index) + size;
// Move the directory index pointer to the next index
index_ptr = (struct squashfs_directory_index *)((char *)index_ptr + sizeof(struct squashfs_directory_index) + size);
// Increment the loop counter
l++;
}
// Return the total size of the large directory inode including indices
return sizeof(struct squashfs_ldir_inode) + index_list_size;
}
case SQFS_LREG_TYPE: {
// Cast the base inode to a large regular file inode structure
struct squashfs_lreg_inode *lreg_inode = (struct squashfs_lreg_inode *)inode;
// Read the fragment and file size fields from the large regular inode
__le32 fragment = get_unaligned_le32(&lreg_inode->fragment);
__le64 file_size = lreg_inode->file_size;
// Declare a variable to hold the block list size
u32 block_list_size;
// Check if the file is not fragmented
if (fragment == 0xFFFFFFFF)
// Calculate block list size for non-fragmented files
block_list_size = (file_size + blk_size - 1) / blk_size;
else
// Calculate block list size for fragmented files
block_list_size = (file_size + blk_size - 1) / blk_size + 1;
// Return the total size of the large regular inode including the block list
return sizeof(struct squashfs_lreg_inode) + block_list_size * sizeof(__le32);
}
case SQFS_SYMLINK_TYPE:
case SQFS_LSYMLINK_TYPE: {
// Cast the base inode to a symlink inode structure
struct squashfs_symlink_inode *symlink_inode = (struct squashfs_symlink_inode *)inode;
// Return the total size of the symlink inode including the symlink path
return sizeof(struct squashfs_symlink_inode) + get_unaligned_le32(&symlink_inode->symlink_size);
}
case SQFS_BLKDEV_TYPE:
case SQFS_CHRDEV_TYPE:
// Return the size of a device inode structure
return sizeof(struct squashfs_dev_inode);
case SQFS_LBLKDEV_TYPE:
case SQFS_LCHRDEV_TYPE:
// Return the size of a large device inode structure
return sizeof(struct squashfs_ldev_inode);
case SQFS_FIFO_TYPE:
case SQFS_SOCKET_TYPE:
// Return the size of an IPC inode structure
return sizeof(struct squashfs_ipc_inode);
case SQFS_LFIFO_TYPE:
case SQFS_LSOCKET_TYPE:
// Return the size of a large IPC inode structure
return sizeof(struct squashfs_lipc_inode);
default:
// Print an error message for unknown inode types
fprintf(stderr, "Unknown inode type: %d\n", get_unaligned_le16(&inode->inode_type));
// Return an error code for invalid inode type
return -1;
}
