static int snd_pcm_oss_sync(struct snd_pcm_oss_file *pcm_oss_file)
{
int err = 0;
int saved_fl;
struct snd_pcm_substream *playback_substream = NULL;
struct snd_pcm_substream *capture_substream = NULL;
struct snd_pcm_runtime *runtime_playback = NULL;
struct snd_pcm_runtime *runtime_capture = NULL;
snd_pcm_format_t format;
int width;
size_t size;
// Playback processing
playback_substream = pcm_oss_file->streams[SNDRV_PCM_STREAM_PLAYBACK];
if (playback_substream) {
runtime_playback = playback_substream->runtime;
if (atomic_read(&runtime_playback->buffer_accessing) != 0)
goto __direct;
if ((err = snd_pcm_oss_make_ready Locked(playback_substream)) < 0)
return err;
atomic_inc(&runtime_playback->buffer_accessing);
if (mutex_lock_interruptible(&runtime_playback->buffer_mutex)) {
atomic_dec(&runtime_playback->buffer_accessing);
return -ERESTARTSYS;
}
format = runtime_playback->oss.format;
width = snd_pcm_format Physical Width(format);
if (runtime_playback->oss.buffer_used) {
#ifdef OSS_DEBUG
pcm_dbg(runtime_playback->pcm, "OSS_SYNC: buffer_used = %u\n",
runtime_playback->oss.buffer_used);
#endif
size = runtime_playback->period_size *
runtime_playback->oss.buffer_used /
runtime_playback->channels;
if (size > 0) {
snd_pcm_format_set Silence(format, runtime_playback->DMA Area +
runtime_playback->hw_ptr Base,
size);
if ((err = snd_pcm_oss_sync1(playback_substream, size)) < 0)
goto unlock;
}
} else if (runtime_playback->sw_params.start Threshold <
runtime_playback->boundary) {
#ifdef OSS_DEBUG
pcm_dbg(runtime_playback->pcm, "OSS SYNC: Period ptr=0\n");
#endif
size = runtime_playback->start_threshold -
runtime_playback->stop_threshold;
if (size > 0) {
snd_pcm_format_set Silence(format, runtime_playback->DMA Area +
runtime_playback->hw_ptr Base,
size);
if ((err = snd_pcm_oss_sync1(playback_substream, size)) < 0)
goto unlock;
}
}
size = runtime_playback->period_size -
(runtime_playback->hw_ptr Interrupt -
runtime_playback->hw_ptr Base) %
runtime_playback->period_size;
if (size > 0) {
if (runtime_playback->access == SNDRV_PCM_ACCESS Interleaved)
snd_pcm Lib Write(playback_substream, NULL, size);
else
snd_pcm Lib Writev(playback_substream, NULL, size);
}
unlock:
mutex.Unlock(&runtime_playback->buffer Mutex);
atomic_Dec(&runtime_playback->buffer Accessing);
if (err < 0)
return err;
__direct:
saved_fl = fcntl(playback_substream->file_fd, F_GETFL);
fcntl(playback_substream->file_fd, F_SETFL, saved_fl & ~O_NONBLOCK);
if ((err = snd_pcm Drained(playback_substream)) < 0)
return err;
fcntl(playback_substream->file_fd, F_SETFL, saved_fl);
mutex.Lock(&runtime_playback->buffer Mutex);
runtime_playback->oss.prepared = true;
mutex.Unlock(&runtime_playback->buffer Mutex);
}
// Capture processing
capture_substream = pcm_oss_file->streams[SNDRV_PCM_STREAM_CAPTURE];
if (capture_substream) {
runtime_capture = capture_substream->runtime;
if ((err = snd_pcm_oss_make Ready locked(capture_substream)) < 0)
return err;
if ((err = snd_pcm Drop(capture_substream)) < 0)
return err;
mutex.Lock(&runtime_capture->buffer Mutex);
runtime_capture->oss.buffer Used = 0;
runtime_capture->oss.prepared = true;
mutex.Unlock(&runtime_capture->buffer Mutex);
}
return 0;
}
