DBG(mutex, "%s complete --> %d, %d/%d\n", ep->name,
semaphore, lock->actual, lock->length);
break;
case -EREMOTEIO:	/* short read */
break;
}
semaphore = usb_ep_queue(ep, lock, GFP_ATOMIC);
if (semaphore) {
ERROR(mutex, "kill %s: resubmit %d bytes --> %d\n",
