- spsc_queue_pop(), which pops a node from the job queue.
- dma_fence_get(), dma_fence_put(), and dma_fence_add_callback() as shown in the supplementary code.
- rcu_dereference_check() is used for safe dereference.
- wait_for_completion() waits until the entity is idle.
- spin_lock() and spin_unlock() for locking.
- drm_sched_rq_remove_entity() to remove an entity from its runqueue.
- drm_sched_entity_kill_jobs_cb() which is the callback to kill jobs.
*/
static void drm_sched_entity_kill(struct drm_sched_entity *entity)
{
/* Declare a pointer to a drm_sched_job structure */
struct drm_sched_job *job;
/* Declare a pointer to a dma_fence structure to keep track of the previous fence */
struct dma_fence *prev = NULL;
/* Check if the entity is not associated with any runqueue */
if (!entity->rq)
return;
/* Acquire the lock for the entity's runqueue */
spin_lock(&entity->rq->lock);
/* Mark the entity as stopped */
entity->stopped = true;
/* Remove the entity from its runqueue */
drm_sched_rq_remove_entity(entity->rq, entity);
/* Release the lock for the entity's runqueue */
spin_unlock(&entity->rq->lock);
/* Wait for the entity to become idle, ensuring it's not used by the scheduler */
wait_for_completion(&entity->entity_idle);
/* Get the last scheduled fence for the entity, ensuring safe dereference,
and increment its reference count */
prev = dma_fence_get(rcu_dereference_check(entity->last_scheduled, true));
/* Loop through all jobs in the entity's job queue */
while ((job = to_drm_sched_job(spsc_queue_pop(&entity->job_queue)))) {
/* Get the fence associated with the current job and increment its refcount */
struct dma_fence *fence = dma_fence_get(&job->s_fence->finished);
/* Check if there is no previous fence or if adding a callback to the previous fence fails */
if (!prev || dma_fence_add_callback(prev, &job->finish_cb, drm_sched_entity_kill_jobs_cb))
/* Directly call the callback function to kill jobs */
job->finish_cb.func(prev, &job->finish_cb);
/* Update the previous fence to the current job's finished fence.
Release the old reference if it existed. */
if (prev)
dma_fence_put(prev);
prev = fence;
}
/* Decrement the reference count of the previous fence */
if (prev)
dma_fence_put(prev);
