static unsigned int default_operstate(const struct net_device *dev)
{
// Check if the network interface is in testing mode
if (netif_testing(dev))
// Return the operational state as testing
return IF_OPER_TESTING;
// Check if the network interface carrier is not okay
if (!netif_carrier_ok(dev)) {
// Get the interface link index
int iflink = dev_get_iflink(dev);
// Declare a pointer for the peer network device
struct net_device *peer;
// Check if the device is unregistered or if the link index is the same as the device index
if (dev->reg_state == NETREG_UNREGISTERED ||
iflink == dev->ifindex)
// Return the operational state as down
return IF_OPER_DOWN;
// Assert that the RTNL lock is held
ASSERT_RTNL();
// Get the peer device by its index
peer = __dev_get_by_index(dev_net(dev), iflink);
// If the peer device is not found, return the operational state as down
if (!peer)
return IF_OPER_DOWN;
// Return the operational state based on the peer's carrier status
return netif_carrier_ok(peer) ? IF_OPER_DOWN :
IF_OPER_LOWERLAYERDOWN;
}
// Check if the network interface is dormant
if (netif_dormant(dev))
// Return the operational state as dormant
return IF_OPER_DORMANT;
// Return the operational state as up
return IF_OPER_UP;
}

