static int rcar_pcie_parse_outbound_ranges(struct rcar_pcie_endpoint *ep,
struct platform_device *pdev)
{
struct rcar_pcie *pcie = &ep->pcie;
char name[32];
struct resource *res;
int count = 0;
int i;
for (i = 0; i < RCAR_PCI_MAX_RESOURCES; i++) {
/* Format the name of the outbound resource based on the index */
snprintf(name, sizeof(name), "ob_range%d", i);
/* Retrieve the resource by name from the platform device */
res = platform_get_resource_byname(pdev, IORESOURCE_MEM, name);
/* Check if the resource was not found */
if (!res) {
/* Log an error message indicating the missing outbound window */
dev_err(pcie->dev, "Missing outbound window: %s\n", name);
/* Return an error code for invalid argument */
return -EINVAL;
}
/* Attempt to request the memory region for the resource */
if (!devm_request_mem_region(pcie->dev, res->start, resource_size(res), name)) {
/* Log an error message indicating the failure to request the memory region */
dev_err(pcie->dev, "Failed to request region for %s\n", name);
/* Return an error code for I/O error */
return -EIO;
}
/* Set the physical base address of the outbound window.
For demonstration purposes, we store the start address in bar_to_atu.
A proper implementation might involve more complex mapping. */
ep->bar_to_atu[count] = (unsigned int)res->start;
/* Set the properties of the outbound window.
Assuming that the ob_window array has been allocated and its elements
have members 'phys_base', 'size', and 'page_size'. */
ep->ob_window[count].phys_base = res->start;
ep->ob_window[count].size = resource_size(res);
/* Set the page size of the outbound window to the size of the window */
ep->ob_window[count].page_size = resource_size(res);
count++;
}
/* Update the number of outbound windows in the endpoint structure */
ep->num_ob_windows = count;
/* Return success */
return 0;
}

