static unsigned long isolate_freepages_block(struct compact_control *cc,
unsigned long *start_pfn,
unsigned long end_pfn,
struct list_head *freelist,
unsigned int stride,
bool strict)
{
/* Initialize variables to track the number of scanned and isolated pages */
unsigned long nr_scanned = 0, total_isolated = 0;
unsigned long blockpfn, isolated;
int order;
unsigned long flags = 0;
bool locked = false;
struct page *page;
/* Set the initial block page frame number (PFN) to the start PFN */
blockpfn = *start_pfn;
/* If strict mode is enabled, set stride to 1 for detailed isolation */
if (strict)
stride = 1;
/* Convert the starting PFN to a page structure */
page = pfn_to_page(blockpfn);
/* Loop through the page frames from start to end, incrementing by stride */
for (; blockpfn < end_pfn; blockpfn += stride, page += stride) {
/* Declare a variable to track the number of isolated pages in this iteration */
unsigned long isolated_this = 0;
/* Periodically release the lock to allow interrupts and check for abort conditions */
if (!(blockpfn % COMPACT_CLUSTER_MAX) &&
compact_unlock_should_abort(&cc->zone->lock, flags, &locked, cc))
break;
/* Increment the number of scanned pages */
nr_scanned++;
/* Check if the current page is a compound page and skip it if possible */
if (PageCompound(page)) {
/* Get the order of the compound page */
order = compound_order(page);
/* If the compound page fits within the end PFN, skip it */
if (blockpfn + (1UL << order) <= end_pfn) {
blockpfn += (1UL << order) - 1;
page += (1UL << order) - 1;
nr_scanned += (1UL << order) - 1;
}
goto isolate_fail;
}
/* Check if the current page is a buddy page */
if (!PageBuddy(page))
goto isolate_fail;
/* If not locked, attempt to acquire the lock */
if (!locked) {
locked = compact_lock_irqsave(&cc->zone->lock, &flags, cc);
/* Recheck if the page is still a buddy page under the lock */
if (!PageBuddy(page))
goto isolate_fail;
}
/* Isolate the free page and break it into order-0 pages */
order = buddy_order(page);
isolated = __isolate_free_page(page, order);
if (!isolated)
break;
set_page_private(page, order);
/* Update the number of scanned and isolated pages */
isolated_this = isolated;
total_isolated += isolated_this;
nr_scanned++;
/* Add the isolated page to the freelist */
list_add_tail(&page->lru, &freelist[order]);
/* If not in strict mode and enough pages are isolated, exit the loop */
if (!strict && cc->nr_migratepages <= cc->nr_freepages) {
blockpfn += isolated_this;
break;
}
/* Advance to the end of the split page */
blockpfn += isolated_this - 1;
page += isolated_this - 1;
continue;
isolate_fail:
/* If in strict mode, exit the loop on failure */
if (strict)
break;
}
/* Release the lock if it was acquired */
if (locked)
spin_unlock_irqrestore(&cc->zone->lock, flags);
/* Ensure the blockpfn does not exceed the end_pfn */
if (unlikely(blockpfn > end_pfn))
blockpfn = end_pfn;
/* Trace the isolation process for debugging */
trace_mm_compaction_isolate_freepages(*start_pfn, blockpfn,
nr_scanned, total_isolated);
/* Update the start_pfn to the current blockpfn */
*start_pfn = blockpfn;
/* If strict mode is enabled, ensure all pages were isolated */
if (strict && blockpfn < end_pfn)
total_isolated = 0;
/* Update the total number of free pages scanned */
cc->total_free_scanned += nr_scanned;
if (total_isolated)
count_compact_events(COMPACTISOLATED, total_isolated);
return total_isolated;
}

struct rxrpc_peer *rxrpc_lookup_peer(struct rxrpc_local *local, struct sockaddr_rxrpc *srx, gfp_t gfp)
{
struct rxrpc_peer *peer, *candidate;
struct rxrpc_net *rxnet = local->rxnet;
unsigned long hash_key = rxrpc_peer_hash_key(local, srx);
_enter("{%pISp}", &srx->transport);
// Lock the RCU read-side critical section to safely traverse the peer list
rcu_read_lock();
// Attempt to find the peer in the hash table using the calculated hash key
peer = __rxrpc_lookup_peer_rcu(local, srx, hash_key);
// If the peer is found, attempt to increment its reference count
if (peer && !rxrpc_get_peer_maybe(peer, rxrpc_peer_get_lookup_client))
// If the reference count increment fails, set peer to NULL
peer = NULL;
// Unlock the RCU read-side critical section
rcu_read_unlock();
// If the peer was not found in the hash table
if (!peer) {
// Create a new candidate peer object
candidate = rxrpc_create_peer(local, srx, hash_key, gfp);
// If candidate creation fails, return NULL
if (!candidate) {
_leave(" = NULL [nomem]");
return NULL;
}
// Lock the peer hash table to safely modify it
spin_lock(&rxnet->peer_hash_lock);
// Recheck the hash table to ensure no race condition occurred
peer = __rxrpc_lookup_peer_rcu(local, srx, hash_key);
// If the peer is found, attempt to increment its reference count
if (peer && !rxrpc_get_peer_maybe(peer, rxrpc_peer_get_lookup_client))
// If the reference count increment fails, set peer to NULL
peer = NULL;
// If the peer is still not found, add the candidate to the hash table
if (!peer) {
hash_add_rcu(rxnet->peer_hash,
&candidate->hash_link, hash_key);
// Add the candidate to the keepalive list
list_add_tail(&candidate->keepalive_link,
&rxnet->peer_keepalive_new);
}
// Unlock the peer hash table
spin_unlock(&rxnet->peer_hash_lock);
// If a peer was found, free the candidate
if (peer)
rxrpc_free_peer(candidate);
else
// Otherwise, use the candidate as the peer
peer = candidate;
}
// Log the result and return the peer
_leave(" = %p {u=%d}", peer, refcount_read(&peer->ref));
return peer;
}

