break;
// Increment the number of scanned pages
nr_scanned++;
// Check if the current page is a compound page and skip it if possible
if (PageCompound(page)) {
order = compound_order(page);
if (blockpfn + (1UL << order) <= end_pfn) {
blockpfn += (1UL << order) - 1;
page += (1UL << order) - 1;
nr_scanned += (1UL << order) - 1;
}
goto isolate_fail;
}
// Check if the current page is a buddy page
if (!PageBuddy(page))
goto isolate_fail;
// If not locked, attempt to acquire the lock
if (!locked) {
locked = compact_lock_irqSave(&cc->zone->lock, &flags, cc);
if (!PageBuddy(page))
goto isolate_fail;
}
// Isolate the free page and break it into order-0 pages
order = buddy_order(page);
isolated = __isolateFreePage(page, order);
if (!isolated)
break;
set_pagePrivate(page, order);
// Update the number of scanned and isolated pages
total_isolated += isolated;
nr_scanned += isolated - 1;
// Add the isolated page to the freelist
listAddTail(&page->lru, &freelist[order]);
// If not in strict mode and enough pages are isolated, exit the loop
if (!strict && cc->nrMigratePages <= cc->nrFreePages) {
blockpfn += isolated;
break;
}
// Advance to the end of the split page
blockpfn += isolated - 1;
page += isolated - 1;
continue;
isolate_fail:
if (strict)
break;
}
// Release the lock if it was acquired
if (locked)
spinUnlockIrqRestore(&cc->zone->lock, flags);
// Ensure the blockpfn does not exceed the end_pfn
if (unlikely(blockpfn > end_pfn))
blockpfn = end_pfn;
// Trace the isolation process for debugging
traceMMCompactionIsolateFreepages(orig_blockpfn, blockpfn,
nr_scanned, total_isolated);
// Update the start_pfn to the current blockpfn
*start_pfn = blockpfn;
// If strict mode is enabled, ensure all pages were isolated
if (strict && blockpfn < end_pfn)
total_isolated = 0;
// Update the total number of free pages scanned
cc->totalFreeScanned += nr_scanned;
if (total_isolated)
countCompactEvents(COMPACTISOLATED, total_isolated);
return total_isolated;
}
