static void geneve_destroy_tunnels(struct net *net, struct list_head *head)
{
/* Retrieve the geneve_net structure associated with the given network namespace.
* We assume that the geneve_net structure is stored as a per-net data via net_generic,
* with an identifier geneve_net_id.
*/
struct geneve_net *gn = net_generic(net, geneve_net_id);
/* Declare pointers for iterating over network devices and geneve devices */
struct net_device *dev, *tmp_dev;
struct geneve_dev *gdev, *tmp_gdev;
/* Iterate over all network devices in the given network namespace */
for_each_netdev_safe(net, dev, tmp_dev) {
/* Check if the device is a geneve device by comparing its link operations.
* We assume that geneve devices have their rtnl_link_ops pointer equal to &geneve_link_ops.
*/
if (dev->rtnl_link_ops == &geneve_link_ops) {
/* If it is a geneve device, unregister it and add it to the provided list */
unregister_netdevice_queue(dev, head);
}
}
/* Iterate over all geneve devices in the geneve_net structure.
* We assume that the geneve_net structure maintains a list head (geneve_list)
* containing all its geneve devices.
*/
list_for_each_entry_safe(gdev, tmp_gdev, &gn->geneve_list, next) {
/* Check if the geneve device is not in the same network namespace.
* We use dev_net() to retrieve the network namespace of gdev->dev.
*/
if (dev_net(gdev->dev) != net) {
/* If it is not, unregister the device and add it to the provided list */
unregister_netdevice_queue(gdev->dev, head);
}
}
} // End of Implementation

