// Declare a pointer to a drm_sched_job structure
struct drm_sched_job *job;
// Declare a pointer to a dma_fence structure to keep track of the previous fence
struct dma_fence *prev = NULL;
// Check if the entity is not associated with any runqueue
if (!entity->rq)
return;
// Acquire the lock for the entity's runqueue
spin_lock(&entity->rq->lock);
// Mark the entity as stopped
entity->stopped = true;
// Remove the entity from its runqueue
list_del_init(&entity->list);
// Release the lock for the entity's runqueue
spin_unlock(&entity->rq->lock);
// Wait for the entity to become idle, ensuring it's not used by the scheduler
wait_for_completion(&entity->entity_idle);
// Get and increment reference count of last scheduled fence safely using RCU read lock.
rcu_read_lock();
prev = rcu_dereference(entity->last_scheduled);
if (prev)
dma_fence_get(prev);
rcu_read_unlock();
// Loop through all jobs in the entity's job queue
while ((job = container_of(spsc_queue_pop(&entity->job_queue), struct drm_sched_job, queue_node))) {
// Get and increment reference count of job's finished fence.
struct dma_fence *fence = &job->s_fence->finished;
dma_fence_get(fence);
// Check if there is no previous fence or if adding a callback to it fails.
if (!prev || dma_fence_add_callback(prev, &job->finish_cb,
drm_sched_entity_kill_jobs_cb))
// Directly call callback function to kill jobs.
drm_sched_entity_kill_jobs_cb(NULL, &job->finish_cb);
// Update previous fence to current job's finished fence and decrement old prev refcount.
dma_fence_put(prev);
prev = fence;
}
// Decrement reference count of final previous fence after loop ends.
dma_fence_put(prev);
}
