{
// Initialize error code to 0
int err = 0;
// Declare a variable to save file flags
unsigned int f_flags;
// Declare a pointer to a PCM substream
struct snd_pcm_substream *playback_substream = NULL;
// Declare a pointer to PCM runtime data
struct snd_pcm_runtime *runtime = NULL;
// Declare a variable for PCM format
snd_pcm_format_t format;
// Declare a variable for the width of the PCM format
int phys_width;
// Declare a variable for size calculations
snd_pcm_uframes_t size_to_fill, total_silent_size = 0;
// Get the playback substream from the OSS file
playback_substream = pcm_oss_file->streams[SNDRV_PCM_STREAM_PLAYBACK];
// Check if the playback substream is not NULL
if (playback_substream) {
// Get the runtime data from the substream
runtime = playback_substream->runtime;
// Check if the mmap count is non-zero
if (atomic_read(&playback_substream->mmap_count))
goto __direct;
// Make the substream ready for playback
if ((err = snd_pcm_oss_make_ready_locked(playback_substream)) < 0)
// Return error if making ready fails
return err;
// Increment the read/write reference count
atomic_inc(&playback_substream->ref_count);
// Lock the parameters mutex, return error if interrupted
if (mutex_lock_interruptible(&runtime->buffer_mutex)) {
// Decrement the read/write reference count
atomic_dec(&playback_substream->ref_count);
// Return restart error
return -ERESTARTSYS;
}
// Get the PCM format from the runtime
format = runtime->format;
// Get the physical width of the PCM format
phys_width = snd_pcm_format_physical_width(format);
// Check if there is used buffer space
if (runtime->oss.buffer_used) {
#ifdef OSS_DEBUG
// Debug log for buffer used
pcm_dbg(playback_substream->pcm, "Buffer used: %lu\n", runtime->oss.buffer_used);
#endif
// Calculate the size of silence to set
total_silent_size = runtime->oss.buffer_used;
// Set silence in the buffer
snd_pcm_format_set_silence(format, runtime->oss.buffer, total_silent_size);
// Sync the substream with the calculated size
if ((err = snd_pcm_oss_sync1(playback_substream, total_silent_size)) < 0)
// Jump to unlock if sync fails
goto unlock;
} else if (runtime->oss.period_pointer) {
#ifdef OSS_DEBUG
// Debug log for period pointer
pcm_dbg(playback_substream->pcm, "Period pointer: %lu\n", runtime->oss.period_pointer);
#endif
// Calculate the size of silence to set
total_silent_size = runtime->oss.period_pointer;
// Set silence in the buffer
snd_pcm_format_set_silence(format, runtime->oss.buffer, total_silent_size);
// Sync the substream with the calculated size
if ((err = snd_pcm_oss_sync1(playback_substream, total_silent_size)) < 0)
// Jump to unlock if sync fails
goto unlock;
}
// Calculate the remaining size in the ALSA period
size_to_fill = runtime->buffer_size - runtime->hw_ptr % runtime->buffer_size;
// Check if there is remaining size to fill
if (size_to_fill) {
// Calculate the size to fill
size_to_fill = MIN(size_to_fill, runtime->avail_min);
// Check the access mode and write silence accordingly
if (runtime->access == SNDRV_PCM_ACCESS_RW_INTERLEAVED)
// Write silence for interleaved access
err = snd_pcm_lib_write(playback_substream, runtime->oss.buffer, size_to_fill);
else if (runtime->access == SNDRV_PCM_ACCESS_RW_NONInterleavEd)
// Write silence for non-interleaved access
err = snd_pcm_lib_writen(playback_substream, runtime->oss.buffer, size_to_fill);
}
unlock:
// Unlock the parameters mutex
mutex_unlock(&runtime->buffer_mutex);
// Decrement the read/write reference count
atomic_dec(&playback_substream->ref_count);
// Return error if any occurred
if (err < 0)
return err;
// Direct handling for mmap count
__direct:
// Save the current file flags
f_flags = runtime->f_flags;
// Clear the non-blocking flag
runtime->f_flags &= ~O_NONBLOCK;
// Drain the PCM buffer
if ((err = snd_pcm_drain_done(playback_substream)) < 0)
// Return error if draining fails
return err;
// Restore the saved file flags
runtime->f_flags = f_flags;
// Lock the parameters mutex
mutex_lock(&runtime->buffer_mutex);
// Set the prepare flag in the runtime
runtime->prepared++;
// Unlock the parameters mutex
mutex_unlock(&runtime->buffer_mutex);
}
// Get the capture substream from the OSS file
struct snd_pcm_substream *capture_substream = pcm_oss_file->streams[SNDRV_PCM_STREAM_CAPTURE];
// Check if the capture substream is not NULL
if (capture_substream) {
// Make the substream ready for capture
if ((err = snd_pcm_oss_make_ready_locked(capture_substream)) < 0)
// Return error if making ready fails
return err;
// Get the runtime data from the substream
runtime = capture_substream->runtime;
// Drop the PCM buffer
if ((err = snd_pcm_drop(capture_substream)) < 0)
// Return error if dropping fails
return err;
// Lock the parameters mutex
mutex_lock(&runtime->buffer_mutex);
// Reset the buffer used and prepare flags in the runtime
runtime->oss.buffer_used = 0;
runtime->oss.params = 0;
// Unlock the parameters mutex
mutex_unlock(&runtime->buffer_mutex);
}
// Return success
return 0;
}

