static void rxrpc_peer_keepalive_dispatch(struct rxrpc_net *rxnet, struct list_head *collector, time64_t base, u8 cursor)
{
// Declare a pointer to an rxrpc_peer structure
struct rxrpc_peer *peer;
// Define a mask for the size of the peer_keepalive array
const u8 mask = 31;
// Declare a variable to store the calculated keepalive time
time64_t keepalive_time;
// Declare a boolean to check if the local endpoint can be used
bool can_use_local;
// Declare a variable to store the slot index
u8 slot;
// Acquire the spin lock for the peer hash
spin_lock(&rxnet->peer_hash_lock);
// Loop while the collector list is not empty
while (!list_empty(collector)) {
// Get the first peer from the collector list
peer = list_entry(collector->next, struct rxrpc_peer, keepalive_link);
// Remove the peer from the collector list and reinitialize its list head
list_del_init(&peer->keepalive_link);
// Attempt to increment the reference count of the peer
peer = rxrpc_get_peer_maybe(peer, RXRPC_PEER_TRACE_KEEPALIVE);
// If the peer reference count could not be incremented, continue to the next peer
if (!peer)
continue;
// Check if the local endpoint can be used for keepalive
can_use_local = __rxrpc_use_local(peer->local, RXRPC_LOCAL_TRACE_KEEPALIVE);
// Release the spin lock for the peer hash
spin_unlock(&rxnet->peer_hash_lock);
// If the local endpoint can be used
if (can_use_local) {
// Calculate the next keepalive time for the peer
keepalive_time = peer->last_tx_at + RXRPC_KEEPALIVE_TIME;
// Calculate the slot index based on the keepalive time
slot = (keepalive_time - base) / RXRPC_KEEPALIVE_TIME;
// Debugging output for the peer and slot
trace_rxrpc_peer(peer->debug_id, slot, RXRPC_PEER_TRACE_KEEPALIVE);
// Check if the keepalive time is outside the valid range
if (keepalive_time < base || keepalive_time >= base + 32 * RXRPC_KEEPALIVE_TIME) {
// Send a keepalive packet to the peer
rxrpc_send_keepalive(peer);
// Set the slot index to the maximum keepalive time
slot = 31;
}
// Adjust the slot index based on the current cursor position
slot += cursor;
// Apply the mask to the slot index
slot &= mask;
// Acquire the spin lock for the peer hash
spin_lock(&rxnet->peer_hash_lock);
// Add the peer to the appropriate slot in the peer_keepalive array
list_add_tail(&peer->keepalive_link, &rxnet->peer_keepalive[slot]);
// Release the spin lock for the peer hash
spin_unlock(&rxnet->peer_hash_lock);
// Decrement the active user count for the local endpoint
rxrpc_unuse_local(peer->local, RXRPC_LOCAL_TRACE_KEEPALIVE);
}
// Decrement the reference count for the peer
rxrpc_put_peer(peer, RXRPC_PEER_TRACE_KEEPALIVE);
// Acquire the spin lock for the peer hash
spin_lock(&rxnet->peer_hash_lock);
}
// Release the spin lock for the peer hash
spin_unlock(&rxnet->peer_hash_lock);
}
